SELECT DISTINCT vid 
FROM runs 
WHERE actual_start_time BETWEEN '2012-10-10 12:00:00' AND '2012-10-10 13:00:00';

SELECT DISTINCT vid 
FROM vehicle_maintenance 
WHERE maintenance_date >= DATE('now', '-6 months');

SELECT email
FROM operators
WHERE hire_date = (SELECT MAX(hire_date) FROM operators);

SELECT vehicle_type, last_maintenance_date
FROM vehicles
WHERE operator_id IN (
  SELECT DISTINCT operator_id
  FROM operator_shifts
);

SELECT maintenance_date, maintenance_type, description
FROM vehicle_maintenance
WHERE vid = '0';
